/** CmmtCodeGroupDao.insert */
insert into cmmt_code_group (
	code_group
	,code_group_nm
	,remark
	,enabled
	,creator_id
	,created_dt
	,updater_id
	,updated_dt
) values (
	upper(#{codeGroup})
	,upper(#{codeGroupNm})
	,#{remark}
	,#{enabled}
	,#{creatorId}
	,#{createdDt}
	,#{updaterId}
	,#{updatedDt}
)

mapper.update:
/** CmmtCodeGroupDao.update */
update cmmt_code_group set
	code_group_nm = upper(#{codeGroupNm})
	,remark       = #{remark}
	,enabled      = #{enabled}
	,creator_id   = #{creatorId}
	,created_dt   = #{createdDt}
	,updater_id   = #{updaterId}
	,updated_dt   = #{updatedDt}
where
	code_group = upper(#{codeGroup})
